13	// RoutingMigrationError signals that the loaded config carries a removed
14	// agent.routing field. The field is gone for good; configs must be migrated
15	// before DDx will load them.
16	type RoutingMigrationError struct {
17		Field string
18		Path  string
19	}
20	
21	func (e *RoutingMigrationError) Error() string {
22		return fmt.Sprintf(
23			"%s: %s has been removed. "+
24				"Migration: delete the field from your .ddx/config.yaml. "+
25				"See docs/migrations/routing-config.md.",
26			e.Path, e.Field)
27	}
28	
29	// checkRoutingMigration parses the raw config bytes and hard-errors on any
30	// removed agent.routing fields.
31	func checkRoutingMigration(path string, data []byte) error {
32		var raw map[string]any
33		if err := yaml.Unmarshal(data, &raw); err != nil {
34			return nil // YAML errors surface from the validator below
35		}
36		agent, _ := raw["agent"].(map[string]any)
37		if agent == nil {
38			return nil
39		}
40		routing, _ := agent["routing"].(map[string]any)
41		if routing == nil {
42			return nil
43		}
44		// routinglint:legacy-rejection reason="hard-error rejection of retired routing keys per ddx-3bd7396a"
45		for _, field := range []string{"default_harness", "profile_ladders", "model_overrides"} {
46			if _, ok := routing[field]; ok {
47				return &RoutingMigrationError{
48					Field: "agent.routing." + field,
49					Path:  path,
50				}
51			}
52		}
53		return nil
54	}
