56	// Type aliases for smooth transition
57	type Config = NewConfig
58	type Repository = RepositoryConfig
59	
60	// ConfigError represents a single configuration error
61	type ConfigError struct {
62		Field      string
63		Value      string
64		Message    string
65		Suggestion string
66	}
67	
68	func (e *ConfigError) Error() string {
69		return fmt.Sprintf("%s: %s", e.Field, e.Message)
70	}
71	
72	// ValidationError represents multiple configuration errors
73	type ValidationError struct {
74		Errors []*ConfigError
75	}
76	
77	func (e *ValidationError) Error() string {
78		if len(e.Errors) == 1 {
79			return e.Errors[0].Error()
80		}
81		return fmt.Sprintf("%d configuration errors found", len(e.Errors))
82	}
