84	// Load loads configuration using the new simplified approach
85	func Load() (*Config, error) {
86		workingDir, err := os.Getwd()
87		if err != nil {
88			return nil, fmt.Errorf("failed to get working directory: %w", err)
89		}
90		return LoadWithWorkingDir(workingDir)
91	}
92	
93	// LoadWithWorkingDir loads configuration from a specific working directory
94	func LoadWithWorkingDir(workingDir string) (*Config, error) {
95		if workingDir == "" {
96			var err error
97			workingDir, err = os.Getwd()
98			if err != nil {
99				return nil, fmt.Errorf("failed to get working directory: %w", err)
100			}
101		}
102	
103		// Use the new ConfigLoader to load from .ddx/config.yaml only
104		loader, err := NewConfigLoaderWithWorkingDir(workingDir)
105		if err != nil {
106			return nil, fmt.Errorf("failed to create config loader: %w", err)
107		}
108	
109		// Pre-validation migration check: surface a friendly hard error for
110		// removed agent.routing fields before the schema validator sees the file.
111		// This happens before LoadConfig so the migration message is what the
112		// operator sees.
113		configPath := filepath.Join(workingDir, ".ddx", "config.yaml")
114		if data, readErr := os.ReadFile(configPath); readErr == nil {
115			if migErr := checkRoutingMigration(configPath, data); migErr != nil {
116				return nil, migErr
117			}
118		}
119	
120		config, err := loader.LoadConfig()
121		if err != nil {
122			// If no config file exists, return default config
123			if os.IsNotExist(err) || strings.Contains(err.Error(), "no configuration file found") {
124				config = DefaultNewConfig()
125			} else {
126				return nil, err
127			}
128		}
129	
130		// Apply defaults to ensure complete configuration
131		config.ApplyDefaults()
132		if config.Agent != nil && config.Agent.Routing != nil &&
133			len(config.Agent.Routing.ProfilePriority) > 0 {
134			fmt.Fprintln(os.Stderr, "warning: agent.routing.profile_priority is deprecated and will be removed in a future version")
135		}
136	
137		// Override library path with environment variable if set
138		if envLibraryPath := os.Getenv("DDX_LIBRARY_BASE_PATH"); envLibraryPath != "" {
139			config.Library.Path = envLibraryPath
140		}
141	
142		// Validate the final configuration
143		if err := config.Validate(); err != nil {
144			return nil, fmt.Errorf("configuration validation failed: %w", err)
145		}
146	
147		return config, nil
148	}
149	
150	// Validate validates the configuration structure and values (simplified)
151	func (c *Config) Validate() error {
152		var errors []*ConfigError
153	
154		// Validate version
155		if c.Version == "" {
156			errors = append(errors, &ConfigError{
157				Field:      "version",
158				Message:    "version is required",
159				Suggestion: "add 'version: \"1.0\"' to your config",
160			})
161		}
162	
163		// Validate library configuration
164		if c.Library != nil && c.Library.Repository != nil {
165			if c.Library.Repository.URL == "" {
166				errors = append(errors, &ConfigError{
167					Field:      "library.repository.url",
168					Message:    "library repository URL is required",
169					Suggestion: "add a valid Git repository URL",
170				})
171			}
172	
173			if c.Library.Repository.Branch == "" {
174				errors = append(errors, &ConfigError{
175					Field:      "library.repository.branch",
176					Message:    "library repository branch is required",
177					Suggestion: "add 'branch: \"main\"' or another valid branch name",
178				})
179			}
180		}
181	
182		if c.Triage != nil {
183			for mode, actions := range c.Triage.Policies {
184				if _, err := triage.ParseFailureMode(mode); err != nil {
185					errors = append(errors, &ConfigError{
186						Field:      "triage.policies." + mode,
187						Value:      mode,
188						Message:    err.Error(),
189						Suggestion: "use review_block, lock_contention, execution_failed, or no_changes",
190					})
191					continue
192				}
193				for i, action := range actions {
194					if _, err := triage.ParseAction(action); err != nil {
195						errors = append(errors, &ConfigError{
196							Field:      fmt.Sprintf("triage.policies.%s[%d]", mode, i),
197							Value:      action,
198							Message:    err.Error(),
199							Suggestion: "use re_attempt_with_context, escalate_tier, retry_with_backoff, file_followup, or operator_required",
200						})
201					}
202				}
203			}
204		}
205	
206		if len(errors) > 0 {
207			return &ValidationError{Errors: errors}
208		}
209	
210		return nil
211	}
