213	// Merge combines this config with another, with the other taking precedence
214	func (c *Config) Merge(other *Config) *Config {
215		result := &Config{
216			Version: c.Version,
217		}
218	
219		// Copy library configuration from base
220		if c.Library != nil {
221			result.Library = &LibraryConfig{
222				Path: c.Library.Path,
223			}
224			if c.Library.Repository != nil {
225				result.Library.Repository = &RepositoryConfig{
226					URL:    c.Library.Repository.URL,
227					Branch: c.Library.Repository.Branch,
228				}
229			}
230		}
231	
232		// Override with other's values
233		if other.Version != "" {
234			result.Version = other.Version
235		}
236		if other.Library != nil {
237			if result.Library == nil {
238				result.Library = &LibraryConfig{}
239			}
240			if other.Library.Path != "" {
241				result.Library.Path = other.Library.Path
242			}
243			if other.Library.Repository != nil {
244				if result.Library.Repository == nil {
245					result.Library.Repository = &RepositoryConfig{}
246				}
247				if other.Library.Repository.URL != "" {
248					result.Library.Repository.URL = other.Library.Repository.URL
249				}
250				if other.Library.Repository.Branch != "" {
251					result.Library.Repository.Branch = other.Library.Repository.Branch
252				}
253			}
254		}
255	
256		return result
257	}
