459	// DefaultRunTest returns a RunTest hook that invokes `go test -run '^<name>$'`
460	// against the given packages (or `./...` if none).
461	func DefaultRunTest(workingDir string) func(name string, packages []string) (bool, string, error) {
462		return func(name string, packages []string) (bool, string, error) {
463			args := []string{"test", "-run", "^" + regexp.QuoteMeta(name) + "$", "-count=1", "-short"}
464			if len(packages) == 0 {
465				args = append(args, "./...")
466			} else {
467				args = append(args, packages...)
468			}
469			cmd := exec.Command("go", args...)
470			cmd.Dir = filepath.Join(workingDir, "cli") // tests live under cli/
471			out, err := cmd.CombinedOutput()
472			text := strings.TrimSpace(string(out))
473			if err != nil {
474				return false, text, nil // test failure surfaces as ok=false, err nil
475			}
476			// `go test` exits 0 also when no tests match; detect that case.
477			if strings.Contains(text, "[no tests to run]") || strings.Contains(text, "no test files") {
478				return false, text + " (no matching test found)", nil
479			}
480			return true, text, nil
481		}
482	}
