659	func resolveClaimAssignee() string {
660		for _, key := range []string{"DDX_AGENT_NAME", "USER", "LOGNAME", "USERNAME", "SUDO_USER"} {
661			if v := os.Getenv(key); v != "" {
662				return v
663			}
664		}
665		return "ddx"
666	}
