692	func beadTransitionOptionsFromSetFlags(status string, setFlags []string, source string) bead.LifecycleTransitionOptions {
693		opts := bead.LifecycleTransitionOptions{
694			Reason: "set lifecycle status",
695			Source: source,
696		}
697		if status == bead.StatusBlocked {
698			for _, kv := range setFlags {
699				k, v, ok := strings.Cut(kv, "=")
700				if ok && k == bead.ExtraLifecycleExternalBlockerReason {
701					opts.ExternalBlockerReason = v
702					break
703				}
704			}
705		}
706		return opts
707	}
