782	func (f *CommandFactory) newBeadCloseCommand() *cobra.Command {
783		cmd := &cobra.Command{
784			Use:   "close <id>",
785			Short: "Close a bead",
786			Args:  cobra.ExactArgs(1),
787			RunE: func(cmd *cobra.Command, args []string) error {
788				if err := f.checkLifecycleMigrationGate(cmd); err != nil {
789					return err
790				}
791				s := f.beadStore()
792				sessionID, _ := cmd.Flags().GetString("session")
793				commitSHA, _ := cmd.Flags().GetString("commit")
794	
795				if commitSHA != "" {
796					normalizedCommitSHA, err := f.resolveCommitSHA(commitSHA)
797					if err != nil {
798						return err
799					}
800					commitSHA = normalizedCommitSHA
801				}
802	
803				target, err := s.Get(args[0])
804				if err != nil {
805					return err
806				}
807				// CloseWithEvidence runs the closure gate (ddx-e30e60a9); manual
808				// operator closes without evidence are intentionally a separate
809				// path. When --session and --commit are both unset, we are in
810				// manual-administration territory — use the ungated Store.Close
811				// so the gate doesn't reject legitimate tracker admin.
812				if sessionID == "" && commitSHA == "" {
813					if err := s.Close(args[0]); err != nil {
814						return err
815					}
816				} else if err := s.CloseWithEvidence(args[0], sessionID, commitSHA); err != nil {
817					return err
818				}
819	
820				landedSHA, err := f.beadAutoCommitIncludingStaged("close " + args[0])
821				if err != nil {
822					return err
823				}
824				if commitSHA == "" && landedSHA != "" {
825					if f.commitIsMetadataOnlyTrackerBackfill(landedSHA) {
826						if isReviewCloseBead(target) {
827							// Tracker-only review-finding closes must not retain any prior
828							// replay boundary. The close commit itself is the metadata-only
829							// backfill, so clear stale closing provenance instead of
830							// preserving an unrelated implementation SHA.
831							if err := s.Update(args[0], func(b *bead.Bead) {
832								if b.Extra == nil {
833									return
834								}
835								delete(b.Extra, "closing_commit_sha")
836							}); err != nil {
837								return err
838							}
839							followupSHA, err := f.beadAutoCommit("close " + args[0])
840							if err != nil {
841								return err
842							}
843							if followupSHA == "" {
844								return fmt.Errorf("close %s: failed to auto-commit closing provenance", args[0])
845							}
846						}
847					} else {
848						// Only stamp closing provenance when the close commit includes
849						// real implementation work. Pure tracker backfills should not
850						// advertise a replay boundary that points at metadata-only
851						// provenance.
852						if err := s.Update(args[0], func(b *bead.Bead) {
853							if b.Extra == nil {
854								b.Extra = make(map[string]any)
855							}
856							b.Extra["closing_commit_sha"] = landedSHA
857						}); err != nil {
858							return err
859						}
