1229	func normalizeChildIDs(children []string) []string {
1230		var out []string
1231		seen := map[string]bool{}
1232		for _, raw := range children {
1233			for _, part := range strings.Split(raw, ",") {
1234				child := strings.TrimSpace(part)
1235				if child == "" || seen[child] {
1236					continue
1237				}
1238				seen[child] = true
1239				out = append(out, child)
1240			}
1241		}
1242		return out
1243	}
1244	
1245	func validateSplitChildren(s *bead.Store, parentID string, children []string) error {
1246		if _, err := s.Get(parentID); err != nil {
1247			return err
1248		}
1249		for _, childID := range children {
1250			if childID == parentID {
1251				return fmt.Errorf("split child cannot be the parent bead: %s", childID)
1252			}
1253			if _, err := s.Get(childID); err != nil {
1254				return fmt.Errorf("split child %s: %w", childID, err)
1255			}
1256		}
1257		return nil
1258	}
