110	func marshalBead(b Bead) ([]byte, error) {
111		m := map[string]any{
112			"id":         b.ID,
113			"title":      b.Title,
114			"status":     b.Status,
115			"priority":   b.Priority,
116			"issue_type": b.IssueType,
117			"created_at": b.CreatedAt,
118			"updated_at": b.UpdatedAt,
119		}
120	
121		// Optional fields — only include if non-empty
122		if b.Owner != "" {
123			m["owner"] = b.Owner
124		}
125		if b.CreatedBy != "" {
126			m["created_by"] = b.CreatedBy
127		}
128		if len(b.Labels) > 0 {
129			m["labels"] = b.Labels
130		}
131		if b.Parent != "" {
132			m["parent"] = b.Parent
133		}
134		if b.Description != "" {
135			m["description"] = b.Description
136		}
137		if b.Acceptance != "" {
138			m["acceptance"] = b.Acceptance
139		}
140		if b.Notes != "" {
141			m["notes"] = b.Notes
142		}
143		if len(b.Dependencies) > 0 {
144			m["dependencies"] = b.Dependencies
145		}
146	
147		// Merge extra fields (workflow-specific)
148		for k, v := range b.Extra {
149			if !knownFields[k] {
150				m[k] = v
151			}
152		}
153	
154		return json.Marshal(m)
155	}
