193	// for callers that need a single uniform shape (notably JSON output and
194	// export-for-interchange paths). It does not touch the on-disk row; the bead
195	// value is mutated in memory only.
196	func (s *Store) LoadEventsInline(b *Bead) error {
197		return s.inlineEventsInPlace(b)
198	}
