200	// inlineEventsInPlace is the inverse of externalizeEventsInPlace: it loads any
201	// sidecar events back into Extra["events"] and clears the attachment ref.
202	// Used by Reopen so an active bead returns to fully-inline storage, and by
203	// the export path which inlines transiently for marshaling without touching
204	// the on-disk row (callers that don't want the bead mutated must work on a
205	// copy — Bead is a value type so the typical usage is to pass a copy).
206	func (s *Store) inlineEventsInPlace(b *Bead) error {
207		if b == nil {
208			return nil
209		}
210		if s.axonGraphQLActive() {
211			return nil
212		}
213		if !hasEventsAttachment(b) {
214			return nil
215		}
216		events, err := s.readEventsAttachment(b.ID)
217		if err != nil {
218			return err
219		}
220		if b.Extra == nil {
221			b.Extra = make(map[string]any)
222		}
223		if len(events) > 0 {
224			b.Extra["events"] = encodeEventsForExtra(events)
225		} else {
226			delete(b.Extra, "events")
227		}
228		delete(b.Extra, EventsAttachmentExtraKey)
229		return nil
230	}
