// IntakeConfig configures the pre-claim intake gates.
type IntakeConfig struct {
	ACQuality *IntakeACQualityConfig `yaml:"ac_quality,omitempty" json:"ac_quality,omitempty"`
}

// IntakeACQualityConfig controls the AC mechanical-verifiability gate.
// MinScore is the minimum fraction of ACs that must be classifiable as
// non-prose for a bead to be execution-eligible. Default is 0.5.
type IntakeACQualityConfig struct {
	MinScore *float64 `yaml:"min_score,omitempty" json:"min_score,omitempty"`
}

// ResolveIntakeACQualityMinScore returns the effective AC quality threshold.
// Defaults to 0.5 when unset or negative.
func (c *NewConfig) ResolveIntakeACQualityMinScore() float64 {
	const defaultMinScore = 0.5
	if c == nil || c.Intake == nil || c.Intake.ACQuality == nil || c.Intake.ACQuality.MinScore == nil {
		return defaultMinScore
	}
	if *c.Intake.ACQuality.MinScore < 0 {
		return defaultMinScore
	}
	return *c.Intake.ACQuality.MinScore
}

