package agent

import (
	"context"
	"encoding/json"
	"fmt"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/bead/accheck"
)

const labelACQualityNeedsRefinement = "ac-quality:needs-refinement"

// ACQualityResult holds the verifiability score and per-AC classifications
// computed by ScoreACQuality.
type ACQualityResult struct {
	Score           float64        // verifiable_count / total; 0 when total == 0
	VerifiableCount int
	ProseCount      int
	Total           int
	Items           []accheck.Item
}

// ScoreACQuality parses acceptance text and computes a mechanical
// verifiability score: verifiable_count / total, where verifiable means any
// Kind other than KindProse. Returns a zero-value result when there are no ACs.
func ScoreACQuality(acceptance string) ACQualityResult {
	items := accheck.ParseAcceptance(acceptance)
	if len(items) == 0 {
		return ACQualityResult{}
	}
	var verifiable, prose int
	for _, item := range items {
		if item.Kind == accheck.KindProse {
			prose++
		} else {
			verifiable++
		}
	}
	return ACQualityResult{
		Score:           float64(verifiable) / float64(len(items)),
		VerifiableCount: verifiable,
		ProseCount:      prose,
		Total:           len(items),
		Items:           items,
	}
}

// CheckACQuality computes the AC quality score for the named bead and, when
// the score falls below threshold, marks the bead ineligible for execution,
// adds the "ac-quality:needs-refinement" label, and emits an "ac-quality-low"
// event with per-AC classifications in the body. Returns (true, nil) when the
// bead passes the quality gate (score >= threshold or no ACs found).
func CheckACQuality(ctx context.Context, s *bead.Store, beadID string, threshold float64) (bool, error) {
	b, err := s.Get(beadID)
	if err != nil {
		return false, fmt.Errorf("ac-quality: get bead %s: %w", beadID, err)
	}
	if b == nil {
		return false, fmt.Errorf("ac-quality: bead %s not found", beadID)
	}

	result := ScoreACQuality(b.Acceptance)
	if result.Total == 0 || result.Score >= threshold {
		return true, nil
	}

	// Below threshold: mark ineligible and add label.
	if err := s.Update(beadID, func(bb *bead.Bead) {
		if bb.Extra == nil {
			bb.Extra = make(map[string]any)
		}
		bb.Extra["execution-eligible"] = false
		var hasLabel bool
		for _, l := range bb.Labels {
			if l == labelACQualityNeedsRefinement {
				hasLabel = true
				break
			}
		}
		if !hasLabel {
			bb.Labels = append(bb.Labels, labelACQualityNeedsRefinement)
		}
	}); err != nil {
		return false, fmt.Errorf("ac-quality: update bead %s: %w", beadID, err)
	}

	// Build per-AC classification body for the event.
	type itemEntry struct {
		AC   int    `json:"ac"`
		Text string `json:"text"`
		Kind string `json:"kind"`
	}
	entries := make([]itemEntry, len(result.Items))
	for i, item := range result.Items {
		entries[i] = itemEntry{AC: item.AC, Text: item.Text, Kind: string(item.Kind)}
	}
	body, _ := json.Marshal(map[string]any{
		"score":            result.Score,
		"verifiable_count": result.VerifiableCount,
		"prose_count":      result.ProseCount,
		"total":            result.Total,
		"threshold":        threshold,
		"items":            entries,
	})

	if err := s.AppendEvent(beadID, bead.BeadEvent{
		Kind:    "ac-quality-low",
		Summary: fmt.Sprintf("AC verifiability %.2f below threshold %.2f (%d/%d mechanical)", result.Score, threshold, result.VerifiableCount, result.Total),
		Body:    string(body),
		Source:  "ddx pre-claim ac-quality",
	}); err != nil {
		return false, fmt.Errorf("ac-quality: append event %s: %w", beadID, err)
	}

	return false, nil
}

package cmd

import (
	"encoding/json"
	"fmt"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/spf13/cobra"
)

// newBeadLintCommand wires `ddx bead lint <id>` — ad-hoc AC quality check
// that prints per-AC classification and verifiability score without modifying
// the bead. Operators use this to self-check before filing or dispatching.
func (f *CommandFactory) newBeadLintCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "lint <bead-id>",
		Short: "Lint AC verifiability and print the mechanical score",
		Long: `lint classifies each acceptance criterion by kind and computes a
verifiability score (verifiable_count / total). Items classified as
test-name, build-gate, negative, symbol, or mechanical count as
verifiable; prose items do not.

The default threshold is 0.5; override via intake.ac_quality.min_score
in .ddx/config.yaml.

Examples:
  ddx bead lint ddx-abc123
  ddx bead lint ddx-abc123 --json`,
		Args: cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			beadID := args[0]
			s := f.beadStore()
			b, err := s.Get(beadID)
			if err != nil {
				return fmt.Errorf("bead %s: %w", beadID, err)
			}
			if b == nil {
				return fmt.Errorf("bead %s not found", beadID)
			}

			result := agent.ScoreACQuality(b.Acceptance)
			asJSON, _ := cmd.Flags().GetBool("json")

			if asJSON {
				type itemOut struct {
					AC   int    `json:"ac"`
					Text string `json:"text"`
					Kind string `json:"kind"`
				}
				items := make([]itemOut, len(result.Items))
				for i, item := range result.Items {
					items[i] = itemOut{AC: item.AC, Text: item.Text, Kind: string(item.Kind)}
				}
				out := map[string]any{
					"bead_id":          beadID,
					"score":            result.Score,
					"verifiable_count": result.VerifiableCount,
					"prose_count":      result.ProseCount,
					"total":            result.Total,
					"items":            items,
				}
				blob, err := json.MarshalIndent(out, "", "  ")
				if err != nil {
					return err
				}
				fmt.Fprintln(cmd.OutOrStdout(), string(blob))
				return nil
			}

			fmt.Fprintf(cmd.OutOrStdout(), "bead lint: %s\n", beadID)
			fmt.Fprintf(cmd.OutOrStdout(), "score: %.2f (%d/%d mechanical)\n\n", result.Score, result.VerifiableCount, result.Total)
			for _, item := range result.Items {
				fmt.Fprintf(cmd.OutOrStdout(), "AC #%d  [%-13s]  %s\n", item.AC, item.Kind, truncateLint(item.Text, 80))
			}
			return nil
		},
	}
	cmd.Flags().Bool("json", false, "Output as JSON")
	return cmd
}

func truncateLint(s string, n int) string {
	if len(s) <= n {
		return s
	}
	return s[:n-1] + "…"
}

